module Kreuzberg
  # Format-specific metadata (discriminated union).
  #
  # Only one format type can exist per extraction result. This provides
  # type-safe, clean metadata without nested optionals.
  module FormatMetadata2
    extend T::Helpers
    extend T::Sig

    interface!

    # Dispatch from a Hash to the appropriate variant constructor.
    # @param hash [Hash] with discriminator field and variant-specific fields
    # @return [variant_class] an instance of the appropriate variant
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.untyped) }
    def self.from_hash(hash)
      discriminator = hash[:format_type] || hash['format_type']
      case discriminator
      when 'pdf' then FormatMetadata2Pdf.from_hash(hash)
      when 'docx' then FormatMetadata2Docx.from_hash(hash)
      when 'excel' then FormatMetadata2Excel.from_hash(hash)
      when 'email' then FormatMetadata2Email.from_hash(hash)
      when 'pptx' then FormatMetadata2Pptx.from_hash(hash)
      when 'archive' then FormatMetadata2Archive.from_hash(hash)
      when 'image' then FormatMetadata2Image.from_hash(hash)
      when 'xml' then FormatMetadata2Xml.from_hash(hash)
      when 'text' then FormatMetadata2Text.from_hash(hash)
      when 'html' then FormatMetadata2Html.from_hash(hash)
      when 'ocr' then FormatMetadata2Ocr.from_hash(hash)
      when 'csv' then FormatMetadata2Csv.from_hash(hash)
      when 'bibtex' then FormatMetadata2Bibtex.from_hash(hash)
      when 'citation' then FormatMetadata2Citation.from_hash(hash)
      when 'fiction_book' then FormatMetadata2FictionBook.from_hash(hash)
      when 'dbf' then FormatMetadata2Dbf.from_hash(hash)
      when 'jats' then FormatMetadata2Jats.from_hash(hash)
      when 'epub' then FormatMetadata2Epub.from_hash(hash)
      when 'pst' then FormatMetadata2Pst.from_hash(hash)
      when 'code' then FormatMetadata2Code.from_hash(hash)
      else raise "Unknown discriminator: #{discriminator}"
      end
    end
  end

